files.content:
.root {
  display: flex;
  align-items: center;
  gap: var(--moduix-spacing-3);
  width: 100%;
  min-height: var(--moduix-size-xl);
  padding: var(--moduix-spacing-2) var(--moduix-spacing-3);
  border: var(--moduix-border-width-sm) solid var(--moduix-color-border);
  border-radius: var(--moduix-radius-lg);
  background-color: var(--moduix-color-card);
  color: var(--moduix-color-card-foreground);
}

.brand {
  display: inline-flex;
  align-items: center;
  color: inherit;
  text-decoration: none;
}

.brandMark {
  display: grid;
  place-items: center;
  width: var(--moduix-size-sm);
  height: var(--moduix-size-sm);
  border-radius: var(--moduix-radius-sm);
  background-color: var(--moduix-color-foreground);
  color: var(--moduix-color-background);
  font-size: var(--moduix-text-xs);
  font-weight: var(--moduix-weight-semibold);
  line-height: 1;
}

.navigation {
  display: flex;
  align-items: center;
  gap: var(--moduix-spacing-1);
}

.navigationLink {
  padding: var(--moduix-spacing-1) var(--moduix-spacing-2);
  border-radius: var(--moduix-radius-sm);
  color: var(--moduix-color-muted-foreground);
  font-size: var(--moduix-text-sm);
  text-decoration: none;

  &[data-active],
  &:hover {
    background-color: var(--moduix-color-muted);
    color: var(--moduix-color-foreground);
  }
}

.actions {
  display: flex;
  align-items: center;
  gap: var(--moduix-spacing-2);
  margin-inline-start: auto;
}

.iconButton {
  position: relative;
}

.notificationCount {
  display: grid;
  place-items: center;
  position: absolute;
  inset-block-start: -0.25rem;
  inset-inline-end: -0.25rem;
  width: 1.25rem;
  height: 1.25rem;
  padding: 0;
  border: var(--moduix-border-width-sm) solid var(--moduix-color-card);
  border-radius: var(--moduix-radius-full);
  font-size: 0.625rem;
  line-height: 1;
}

.notificationsMenu {
  --moduix-menu-popup-min-width: 20rem;
}

.notification {
  display: grid;
  gap: var(--moduix-spacing-1);
  color: var(--moduix-color-muted-foreground);
  font-size: var(--moduix-text-sm);
  line-height: var(--moduix-line-height-text-sm);
  text-decoration: none;
}

.notificationTitle {
  color: var(--moduix-color-foreground);
  font-weight: var(--moduix-weight-medium);
}

.account {
  gap: var(--moduix-spacing-2);
  padding-inline: var(--moduix-spacing-1);
}

.accountLabel {
  display: grid;
  min-width: 0;
  text-align: start;
}

.accountLabel strong,
.accountLabel span {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.accountLabel strong {
  font-size: var(--moduix-text-sm);
  line-height: var(--moduix-line-height-text-sm);
}

.accountLabel span {
  color: var(--moduix-color-muted-foreground);
  font-size: var(--moduix-text-xs);
  line-height: var(--moduix-line-height-text-xs);
}

.accountMenu {
  --moduix-menu-popup-min-width: 13rem;
}

@media (width < 42rem) {
  .root {
    gap: var(--moduix-spacing-3);
  }

  .navigation,
  .accountLabel,
  .account > [data-slot='menu-indicator'] {
    display: none;
  }
}
